#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return (*y) - (*x);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int scores[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &scores[i]);
        }
        qsort(scores, N, sizeof(int), compare);
        double sum = 0, weight = 0;
        for (int i = 0; i < X; i++) {
            sum += scores[i] * (i + 1);
            weight += (i + 1);
        }
        printf("%.6f\n", sum / weight);
    }
    return 0;
}

