import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int X = sc.nextInt();
            int[] scores = new int[N];
            for (int i = 0; i < N; i++) {
                scores[i] = sc.nextInt();
            }
            Arrays.sort(scores);
            double sum = 0, weight = 0;
            for (int i = N - X; i < N; i++) {
                sum += scores[i] * (i + 1);
                weight += (i + 1);
            }
            System.out.printf("%.6f\n", sum / weight);
        }
    }
}

