const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, X] = nextInts();
    let scores = nextInts();
    scores.sort((a, b) => b - a);
    let sum = 0;
    let weight = 0;
    for (let i = 0; i < X; i++) {
        sum += scores[i] * (i + 1);
        weight += (i + 1);
    }
    console.log(sum / weight.toFixed(6));
}
